from __future__ import annotations
from dataclasses import dataclass
from typing import Union, Optional


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional[ASTNode] = None
    right: Optional[ASTNode] = None
    operand: Optional[ASTNode] = None


class Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.current_char: Optional[str] = None
        self.advance()

    def advance(self):
        if self.pos < len(self.expression):
            self.current_char = self.expression[self.pos]
            self.pos += 1
        else:
            self.current_char = None

    def skip_whitespace(self):
        while self.current_char is not None and self.current_char.isspace():
            self.advance()

    def get_number(self) -> float:
        result = ""
        while self.current_char is not None and (
            self.current_char.isdigit() or self.current_char == "."
        ):
            result += self.current_char
            self.advance()
        return float(result)

    def get_next_token(self) -> tuple[str, Optional[Union[float, str]]]:
        self.skip_whitespace()

        if self.current_char is None:
            return ("EOF", None)

        if self.current_char.isdigit() or (self.current_char == "."):
            return ("NUMBER", self.get_number())

        if self.current_char in "+-*/()":
            char = self.current_char
            self.advance()
            return ("OP", char)

        raise ValueError(f"Invalid token: {self.current_char}")


class Parser:
    def __init__(self, tokenizer: Tokenizer):
        self.tokenizer = tokenizer
        self.current_token = self.tokenizer.get_next_token()

    def eat(self, expected_type: str, expected_value: Optional[str] = None):
        token_type, token_value = self.current_token

        if token_type == "EOF":
            raise ValueError("Unexpected end of expression")

        if token_type != expected_type:
            raise ValueError(f"Expected {expected_type}, got {token_type}")

        if expected_value is not None and token_value != expected_value:
            raise ValueError(f"Expected {expected_value}, got {token_value}")

        self.current_token = self.tokenizer.get_next_token()

    def parse(self) -> ASTNode:
        if self.current_token[0] == "EOF":
            raise ValueError("Empty expression")

        result = self.expr()

        if self.current_token[0] != "EOF":
            raise ValueError("Unexpected token after expression")

        return result

    def expr(self) -> ASTNode:
        return self.additive()

    def additive(self) -> ASTNode:
        left = self.multiplicative()

        while self.current_token[0] == "OP" and self.current_token[1] in ("+", "-"):
            op = self.current_token[1]
            self.eat("OP")
            right = self.multiplicative()
            left = ASTNode(type="binop", op=op, left=left, right=right)

        return left

    def multiplicative(self) -> ASTNode:
        left = self.unary()

        while self.current_token[0] == "OP" and self.current_token[1] in ("*", "/"):
            op = self.current_token[1]
            self.eat("OP")
            right = self.unary()
            left = ASTNode(type="binop", op=op, left=left, right=right)

        return left

    def unary(self) -> ASTNode:
        if self.current_token[0] == "OP" and self.current_token[1] == "-":
            self.eat("OP")
            operand = self.unary()
            return ASTNode(type="unary", op="-", operand=operand)

        if self.current_token[0] == "OP" and self.current_token[1] == "+":
            self.eat("OP")
            return self.unary()

        return self.primary()

    def primary(self) -> ASTNode:
        token_type, token_value = self.current_token

        if token_type == "NUMBER":
            self.eat("NUMBER")
            assert isinstance(token_value, float)
            return ASTNode(type="number", value=token_value)

        if token_type == "OP" and token_value == "(":
            self.eat("OP")
            node = self.expr()
            if self.current_token[0] != "OP" or self.current_token[1] != ")":
                raise ValueError("Unmatched parenthesis")
            self.eat("OP", ")")
            return node

        raise ValueError(f"Unexpected token: {token_value}")


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value

    if node.type == "unary":
        assert node.operand is not None
        operand_value = evaluate(node.operand)
        if node.op == "-":
            return -operand_value
        return operand_value

    if node.type == "binop":
        assert node.left is not None
        assert node.right is not None
        left_value = evaluate(node.left)
        right_value = evaluate(node.right)

        if node.op == "+":
            return left_value + right_value
        elif node.op == "-":
            return left_value - right_value
        elif node.op == "*":
            return left_value * right_value
        elif node.op == "/":
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
            return left_value / right_value

    raise ValueError(f"Unknown node type: {node.type}")
